// /frontend/src/components/Community.jsx
import React from "react";

export default function Community() {
  return (
    <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-4 min-h-[60vh]">
      <div className="text-sm opacity-80 mb-2">Community</div>
      <div className="opacity-70 text-sm">
        Coming soon: ask locals “what’s it like right now?” and share live conditions.
      </div>
    </div>
  );
}
